/**
 * Base trait that all plugins must implement.
 *
 * This trait provides common functionality for plugin lifecycle management,
 * identification, and metadata.
 *
 * # Thread Safety
 *
 * All plugins must be `Send + Sync` to support concurrent usage across threads.
 *
 * # Example
 *
 * ```rust
 * use kreuzberg::plugins::Plugin;
 * use kreuzberg::Result;
 * use std::sync::atomic::{AtomicBool, Ordering};
 *
 * struct MyPlugin {
 * initialized: AtomicBool,
 * }
 *
 * impl Plugin for MyPlugin {
 * fn name(&self) -> &str {
 * "my-plugin"
 * }
 *
 * fn version(&self) -> String {
 * "1.0.0".to_string()
 * }
 *
 * fn initialize(&self) -> Result<()> {
 * self.initialized.store(true, Ordering::Release);
 * println!("Plugin initialized!");
 * Ok(())
 * }
 *
 * fn shutdown(&self) -> Result<()> {
 * self.initialized.store(false, Ordering::Release);
 * println!("Plugin shutdown!");
 * Ok(())
 * }
 * }
 * ```
 */
export declare class JsPlugin {
  /**
   * Returns the unique name/identifier for this plugin.
   *
   * The name should be:
   * - Unique across all plugins
   * - Lowercase with hyphens (e.g., "my-custom-plugin")
   * - URL-safe characters only
   *
   * # Example
   *
   * ```rust
   * # use kreuzberg::plugins::Plugin;
   * # use kreuzberg::Result;
   * # struct MyPlugin;
   * # impl Plugin for MyPlugin {
   * #     fn version(&self) -> String { "1.0.0".to_string() }
   * #     fn initialize(&self) -> Result<()> { Ok(()) }
   * #     fn shutdown(&self) -> Result<()> { Ok(()) }
   * fn name(&self) -> &str {
   * "pdf-extractor"
   * }
   * # }
   * ```
   */
  name(): string
  /**
   * Returns the semantic version of this plugin.
   *
   * Should follow semver format: `MAJOR.MINOR.PATCH`
   *
   * # Example
   *
   * ```rust
   * # use kreuzberg::plugins::Plugin;
   * # use kreuzberg::Result;
   * # struct MyPlugin;
   * # impl Plugin for MyPlugin {
   * #     fn name(&self) -> &str { "my-plugin" }
   * #     fn initialize(&self) -> Result<()> { Ok(()) }
   * #     fn shutdown(&self) -> Result<()> { Ok(()) }
   * fn version(&self) -> String {
   * "1.2.3".to_string()
   * }
   * # }
   * ```
   */
  version(): string
  /**
   * Initialize the plugin.
   *
   * Called once when the plugin is registered. Use this to:
   * - Load configuration
   * - Initialize resources (connections, caches, etc.)
   * - Validate dependencies
   *
   * # Thread Safety
   *
   * This method takes `&self` instead of `&mut self` to work with `Arc<dyn Plugin>`.
   * Plugins needing mutable state during initialization should use interior mutability
   * patterns (Mutex, RwLock, OnceCell, etc.).
   *
   * # Errors
   *
   * Should return an error if initialization fails. The plugin will not be
   * registered if this method returns an error.
   *
   * # Example
   *
   * ```rust
   * # use kreuzberg::plugins::Plugin;
   * # use kreuzberg::Result;
   * # use std::sync::Mutex;
   * # struct MyPlugin { config: Mutex<Option<String>> }
   * # impl Plugin for MyPlugin {
   * #     fn name(&self) -> &str { "my-plugin" }
   * #     fn version(&self) -> String { "1.0.0".to_string() }
   * #     fn shutdown(&self) -> Result<()> { Ok(()) }
   * fn initialize(&self) -> Result<()> {
   * // Load configuration using interior mutability
   * let mut config = self.config.lock().unwrap();
   * *config = Some("loaded".to_string());
   *
   * // Perform any initialization work
   * println!("Plugin initialized successfully");
   *
   * Ok(())
   * }
   * # }
   * ```
   */
  initialize(): void
  /**
   * Shutdown the plugin.
   *
   * Called when the plugin is being unregistered or the application is shutting down.
   * Use this to:
   * - Close connections
   * - Flush caches
   * - Release resources
   *
   * # Thread Safety
   *
   * This method takes `&self` instead of `&mut self` to work with `Arc<dyn Plugin>`.
   * Plugins needing mutable state during shutdown should use interior mutability
   * patterns (Mutex, RwLock, etc.).
   *
   * # Errors
   *
   * Errors during shutdown are logged but don't prevent the shutdown process.
   *
   * # Example
   *
   * ```rust
   * # use kreuzberg::plugins::Plugin;
   * # use kreuzberg::Result;
   * # use std::sync::Mutex;
   * # struct MyPlugin { cache: Mutex<Option<Vec<String>>> }
   * # impl Plugin for MyPlugin {
   * #     fn name(&self) -> &str { "my-plugin" }
   * #     fn version(&self) -> String { "1.0.0".to_string() }
   * #     fn initialize(&self) -> Result<()> { Ok(()) }
   * fn shutdown(&self) -> Result<()> {
   * // Flush caches using interior mutability
   * let mut cache = self.cache.lock().unwrap();
   * if let Some(data) = cache.take() {
   * // Persist cache to disk
   * }
   *
   * Ok(())
   * }
   * # }
   * ```
   */
  shutdown(): void
  /**
   * Optional plugin description for debugging and logging.
   *
   * Defaults to empty string if not overridden.
   */
  description(): string
  /**
   * Optional plugin author information.
   *
   * Defaults to empty string if not overridden.
   */
  author(): string
}

